import{_ as t,o as s,c as n,a4 as l}from"./chunks/framework._in6GHBg.js";const g=JSON.parse('{"title":"代谢计算套路","description":"","frontmatter":{},"headers":[],"relativePath":"biology/routine-metabolism.md","filePath":"biology/routine-metabolism.md"}'),e={name:"biology/routine-metabolism.md"};function i(p,a,r,o,h,d){return s(),n("div",null,[...a[0]||(a[0]=[l(`<h1 id="代谢计算套路" tabindex="-1">代谢计算套路 <a class="header-anchor" href="#代谢计算套路" aria-label="Permalink to &quot;代谢计算套路&quot;">​</a></h1><p><strong>识别类型→明确关系→代入计算→验证结果</strong></p><hr><h2 id="一、题型识别" tabindex="-1">一、题型识别 <a class="header-anchor" href="#一、题型识别" aria-label="Permalink to &quot;一、题型识别&quot;">​</a></h2><h3 id="特征关键词" tabindex="-1">特征关键词 <a class="header-anchor" href="#特征关键词" aria-label="Permalink to &quot;特征关键词&quot;">​</a></h3><ul><li>&quot;光合速率&quot;</li><li>&quot;呼吸速率&quot;</li><li>&quot;净光合&quot;</li><li>&quot;总光合&quot;</li><li>&quot;积累量&quot;</li><li>&quot;有机物增加量&quot;</li></ul><h3 id="典型问法" tabindex="-1">典型问法 <a class="header-anchor" href="#典型问法" aria-label="Permalink to &quot;典型问法&quot;">​</a></h3><ul><li>求总光合速率</li><li>求净光合速率</li><li>求呼吸速率</li><li>求一昼夜有机物积累量</li><li>分析光照/CO₂浓度变化对C₃、C₅含量的影响</li></ul><hr><h2 id="二、核心关系式" tabindex="-1">二、核心关系式 <a class="header-anchor" href="#二、核心关系式" aria-label="Permalink to &quot;二、核心关系式&quot;">​</a></h2><h3 id="_2-1-三个速率的关系" tabindex="-1">2.1 三个速率的关系 <a class="header-anchor" href="#_2-1-三个速率的关系" aria-label="Permalink to &quot;2.1 三个速率的关系&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>总光合速率 = 净光合速率 + 呼吸速率</span></span></code></pre></div><p><strong>理解</strong>：</p><ul><li><strong>总光合速率</strong>（真正光合速率）：植物实际进行光合作用的速率</li><li><strong>净光合速率</strong>（表观光合速率）：测得的光合速率（总光合 - 呼吸）</li><li><strong>呼吸速率</strong>：植物进行呼吸作用的速率</li></ul><h3 id="_2-2-表示方法" tabindex="-1">2.2 表示方法 <a class="header-anchor" href="#_2-2-表示方法" aria-label="Permalink to &quot;2.2 表示方法&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">表示指标</th><th style="text-align:left;">含义</th></tr></thead><tbody><tr><td style="text-align:center;">CO₂吸收量</td><td style="text-align:left;">净光合</td></tr><tr><td style="text-align:center;">CO₂固定量</td><td style="text-align:left;">总光合</td></tr><tr><td style="text-align:center;">CO₂释放量</td><td style="text-align:left;">呼吸</td></tr><tr><td style="text-align:center;">O₂产生量</td><td style="text-align:left;">总光合</td></tr><tr><td style="text-align:center;">O₂释放量</td><td style="text-align:left;">净光合</td></tr><tr><td style="text-align:center;">O₂吸收量</td><td style="text-align:left;">呼吸</td></tr><tr><td style="text-align:center;">有机物产生量/制造量</td><td style="text-align:left;">总光合</td></tr><tr><td style="text-align:center;">有机物积累量</td><td style="text-align:left;">净光合</td></tr><tr><td style="text-align:center;">有机物消耗量</td><td style="text-align:left;">呼吸</td></tr></tbody></table><hr><h2 id="三、解题步骤" tabindex="-1">三、解题步骤 <a class="header-anchor" href="#三、解题步骤" aria-label="Permalink to &quot;三、解题步骤&quot;">​</a></h2><h3 id="类型1-求总光合速率" tabindex="-1">类型1：求总光合速率 <a class="header-anchor" href="#类型1-求总光合速率" aria-label="Permalink to &quot;类型1：求总光合速率&quot;">​</a></h3><p><strong>已知</strong>：净光合速率和呼吸速率 <strong>公式</strong>：总光合 = 净光合 + 呼吸</p><p><strong>示例</strong>：</p><ul><li>植物在光照下吸收CO₂ 10mg/h，黑暗中释放CO₂ 4mg/h</li><li>总光合速率 = 10 + 4 = 14 mg CO₂/h</li></ul><hr><h3 id="类型2-求净光合速率" tabindex="-1">类型2：求净光合速率 <a class="header-anchor" href="#类型2-求净光合速率" aria-label="Permalink to &quot;类型2：求净光合速率&quot;">​</a></h3><p><strong>已知</strong>：总光合速率和呼吸速率 <strong>公式</strong>：净光合 = 总光合 - 呼吸</p><p><strong>示例</strong>：</p><ul><li>植物产生O₂ 20mg/h，呼吸消耗O₂ 5mg/h</li><li>净光合速率 = 20 - 5 = 15 mg O₂/h</li></ul><hr><h3 id="类型3-求有机物积累量-一昼夜" tabindex="-1">类型3：求有机物积累量（一昼夜） <a class="header-anchor" href="#类型3-求有机物积累量-一昼夜" aria-label="Permalink to &quot;类型3：求有机物积累量（一昼夜）&quot;">​</a></h3><p><strong>公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>一昼夜有机物积累量 = 白天净光合积累量 - 夜间呼吸消耗量</span></span>
<span class="line"><span>                    = 总光合 × 光照时间 - 呼吸 × 24小时</span></span></code></pre></div><p><strong>示例</strong>：</p><ul><li>植物净光合速率10mg/h，呼吸速率4mg/h，光照12小时</li><li>白天积累 = 10 × 12 = 120 mg</li><li>夜间消耗 = 4 × 12 = 48 mg</li><li>一昼夜积累 = 120 - 48 = 72 mg</li></ul><hr><h3 id="类型4-c3、c5含量变化分析" tabindex="-1">类型4：C₃、C₅含量变化分析 <a class="header-anchor" href="#类型4-c3、c5含量变化分析" aria-label="Permalink to &quot;类型4：C₃、C₅含量变化分析&quot;">​</a></h3><p><strong>原理</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CO₂ + C₅ → 2C₃（CO₂固定）</span></span>
<span class="line"><span>2C₃ + [H] + ATP → (CH₂O) + C₅（C₃还原）</span></span></code></pre></div><p><strong>分析方法</strong>：</p><ol><li><p><strong>光照增强</strong>（[H]、ATP增多）：</p><ul><li>C₃还原加快 → C₃减少</li><li>C₅生成增多 → C₅增多</li></ul></li><li><p><strong>光照减弱</strong>（[H]、ATP减少）：</p><ul><li>C₃还原减慢 → C₃增多</li><li>C₅生成减少 → C₅减少</li></ul></li><li><p><strong>CO₂浓度升高</strong>：</p><ul><li>CO₂固定加快 → C₃生成增多 → C₃增多</li><li>C₅消耗增多 → C₅减少</li></ul></li><li><p><strong>CO₂浓度降低</strong>：</p><ul><li>CO₂固定减慢 → C₃生成减少 → C₃减少</li><li>C₅消耗减少 → C₅增多</li></ul></li></ol><p><strong>记忆口诀</strong>：</p><ul><li>&quot;光多C₃少，光少C₃多&quot;</li><li>&quot;碳多C₃多，碳少C₃少&quot;</li><li>&quot;C₅与C₃相反&quot;</li></ul><hr><h2 id="四、标准格式" tabindex="-1">四、标准格式 <a class="header-anchor" href="#四、标准格式" aria-label="Permalink to &quot;四、标准格式&quot;">​</a></h2><h3 id="计算题答题模板" tabindex="-1">计算题答题模板 <a class="header-anchor" href="#计算题答题模板" aria-label="Permalink to &quot;计算题答题模板&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：由题意可知：</span></span>
<span class="line"><span>    [列出已知条件]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    根据[公式/原理]：</span></span>
<span class="line"><span>    [列出计算式]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    计算得：[结果]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    答：[最终答案]</span></span></code></pre></div><hr><h2 id="五、典型例题" tabindex="-1">五、典型例题 <a class="header-anchor" href="#五、典型例题" aria-label="Permalink to &quot;五、典型例题&quot;">​</a></h2><h3 id="例题1-基本计算" tabindex="-1">例题1：基本计算 <a class="header-anchor" href="#例题1-基本计算" aria-label="Permalink to &quot;例题1：基本计算&quot;">​</a></h3><p><strong>题目</strong>：某植物在25℃、光照强度为1000lux时，测得CO₂吸收量为12mg/h；在黑暗中，测得CO₂释放量为4mg/h。求：</p><ul><li>(1) 总光合速率</li><li>(2) 净光合速率</li><li>(3) 呼吸速率</li></ul><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：由题意可知：</span></span>
<span class="line"><span>    净光合速率 = CO₂吸收量 = 12 mg/h</span></span>
<span class="line"><span>    呼吸速率 = CO₂释放量（黑暗）= 4 mg/h</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    (1) 总光合速率 = 净光合速率 + 呼吸速率</span></span>
<span class="line"><span>                    = 12 + 4</span></span>
<span class="line"><span>                    = 16 mg CO₂/h</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    (2) 净光合速率 = 12 mg CO₂/h</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    (3) 呼吸速率 = 4 mg CO₂/h</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    答：总光合速率为16mg CO₂/h，净光合速率为12mg CO₂/h，呼吸速率为4mg CO₂/h。</span></span></code></pre></div><hr><h3 id="例题2-一昼夜积累" tabindex="-1">例题2：一昼夜积累 <a class="header-anchor" href="#例题2-一昼夜积累" aria-label="Permalink to &quot;例题2：一昼夜积累&quot;">​</a></h3><p><strong>题目</strong>：某植物在白天（光照12小时）净光合速率为15mg/h，呼吸速率为5mg/h。求一昼夜有机物的积累量。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：白天积累量 = 净光合速率 × 光照时间</span></span>
<span class="line"><span>                = 15 × 12</span></span>
<span class="line"><span>                = 180 mg</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    夜间消耗量 = 呼吸速率 × 黑暗时间</span></span>
<span class="line"><span>               = 5 × 12</span></span>
<span class="line"><span>               = 60 mg</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    一昼夜积累量 = 白天积累量 - 夜间消耗量</span></span>
<span class="line"><span>                 = 180 - 60</span></span>
<span class="line"><span>                 = 120 mg</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    答：一昼夜有机物积累量为120mg。</span></span></code></pre></div><hr><h3 id="例题3-c3、c5含量变化" tabindex="-1">例题3：C₃、C₅含量变化 <a class="header-anchor" href="#例题3-c3、c5含量变化" aria-label="Permalink to &quot;例题3：C₃、C₅含量变化&quot;">​</a></h3><p><strong>题目</strong>：正常光照下，某植物细胞内C₃和C₅含量保持动态平衡。若突然降低光照强度，短时间内C₃和C₅的含量如何变化？为什么？</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>答：突然降低光照强度，光反应产生的[H]和ATP减少，C₃还原速率减慢，</span></span>
<span class="line"><span>    而CO₂固定速率暂时不变，C₃生成速率不变，导致C₃含量增加；</span></span>
<span class="line"><span>    同时C₅生成速率减慢，而C₅消耗速率暂时不变，导致C₅含量减少。</span></span></code></pre></div><hr><h2 id="六、易错点清单" tabindex="-1">六、易错点清单 <a class="header-anchor" href="#六、易错点清单" aria-label="Permalink to &quot;六、易错点清单&quot;">​</a></h2><h3 id="审题阶段" tabindex="-1">审题阶段 <a class="header-anchor" href="#审题阶段" aria-label="Permalink to &quot;审题阶段&quot;">​</a></h3><ul><li>[ ] 区分&quot;产生&quot;、&quot;释放&quot;、&quot;吸收&quot;、&quot;固定&quot;</li><li>[ ] 注意单位是否统一</li><li>[ ] 注意时间（一昼夜 vs 白天）</li></ul><h3 id="计算阶段" tabindex="-1">计算阶段 <a class="header-anchor" href="#计算阶段" aria-label="Permalink to &quot;计算阶段&quot;">​</a></h3><ul><li>[ ] 公式是否正确？（总光合 = 净光合 + 呼吸）</li><li>[ ] 时间是否换算正确？</li></ul><h3 id="分析阶段" tabindex="-1">分析阶段 <a class="header-anchor" href="#分析阶段" aria-label="Permalink to &quot;分析阶段&quot;">​</a></h3><ul><li>[ ] 光照变化影响光反应，进而影响C₃还原</li><li>[ ] CO₂变化影响暗反应，进而影响CO₂固定</li></ul><hr><h2 id="七、得分点提示" tabindex="-1">七、得分点提示 <a class="header-anchor" href="#七、得分点提示" aria-label="Permalink to &quot;七、得分点提示&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">步骤</th><th style="text-align:left;">得分点</th></tr></thead><tbody><tr><td style="text-align:center;">列已知</td><td style="text-align:left;">写出各速率数值</td></tr><tr><td style="text-align:center;">选公式</td><td style="text-align:left;">写出计算关系式</td></tr><tr><td style="text-align:center;">计算</td><td style="text-align:left;">计算过程</td></tr><tr><td style="text-align:center;">结论</td><td style="text-align:left;">带单位的最终答案</td></tr></tbody></table><hr><p><strong>文档编号</strong>: Bio-Review-Routine-005<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,75)])])}const u=t(e,[["render",i]]);export{g as __pageData,u as default};
